HJFacePointsMadeup::~HJFacePointsMadeup()
{
	m_facePointsVector.clear();
}
void HJFacePointsMadeup::priConstruct(HJPointf f0, HJPointf f1, HJPointf f2, HJPointf f3, HJPointf f4, HJPointf f5, HJPointf f6, HJPointf f7, HJPointf f8)
{
	std::shared_ptr<HJFacePointsReal> pt = std::make_shared<HJFacePointsReal>(m_width, m_height, true);
	pt->add(f0);
	pt->add(f1);
	pt->add(f2);
	pt->add(f3);
	pt->add(f4);

	pt->add(f5);
	pt->add(f6);
	pt->add(f7);
	pt->add(f8);

	m_facePointsVector.push_back(pt);
}
int HJFacePointsMadeup::getWidth()
{
	return m_width;
}
int HJFacePointsMadeup::getHeight()
{
	return m_height;
}
int HJFacePointsMadeup::getFrameCnt()
{
	return m_facePointsVector.size();
}
std::shared_ptr<HJFacePointsReal> HJFacePointsMadeup::getFacePoints(int i_imgIdx, int& o_imgIdx)
{
	if (m_facePointsVector.empty())
	{
        return nullptr;
	}

	int useIdx = i_imgIdx;
	if (i_imgIdx == -1)
	{
		useIdx = m_index;
	}
	o_imgIdx = useIdx;
	std::shared_ptr<HJFacePointsReal> points = m_facePointsVector[useIdx];

	m_index++;
	if (m_index >= m_facePointsVector.size())
	{
        m_index = 0;
	}
    return points;
}
